class Solution:
    def maximizeXorAndXor(self, nums):
        n = len(nums)
        full = (1 << n) - 1
        best = 0
        BITS = 31
        for b in range(0, full + 1):
            andb = 0
            first = True
            t = 0
            for i in range(n):
                if b & (1 << i):
                    andb = nums[i] if first else (andb & nums[i])
                    first = False
                else:
                    t ^= nums[i]
            mask = ~t
            basis = [0] * BITS
            for i in range(n):
                if b & (1 << i):
                    continue
                x = nums[i] & mask
                for bit in range(BITS - 1, -1, -1):
                    if not (x >> bit) & 1:
                        continue
                    if basis[bit] == 0:
                        basis[bit] = x
                        break
                    x ^= basis[bit]
            cur = 0
            for bit in range(BITS - 1, -1, -1):
                if basis[bit] and (cur ^ basis[bit]) > cur:
                    cur ^= basis[bit]
            andval = andb if not first else 0
            best = max(best, andval + t + 2 * cur)
        return best

