var maximizeXorAndXor = function(nums) {
    const n = nums.length;
    const full = (1 << n) - 1;
    let best = 0;
    const BITS = 31;
    for (let b = 0; b <= full; b++) {
        let andb = 0;
        let first = true;
        let t = 0;
        for (let i = 0; i < n; i++) {
            if (b & (1 << i)) {
                andb = first ? nums[i] : (andb & nums[i]);
                first = false;
            } else {
                t ^= nums[i];
            }
        }
        const mask = ~t;
        const basis = new Array(BITS).fill(0);
        for (let i = 0; i < n; i++) {
            if (b & (1 << i)) continue;
            let x = nums[i] & mask;
            for (let bit = BITS - 1; bit >= 0; bit--) {
                if (!((x >>> bit) & 1)) continue;
                if (basis[bit] === 0) { basis[bit] = x; break; }
                x ^= basis[bit];
            }
        }
        let cur = 0;
        for (let bit = BITS - 1; bit >= 0; bit--) {
            if (basis[bit] && (cur ^ basis[bit]) > cur) cur ^= basis[bit];
        }
        const andval = first ? 0 : andb;
        const cand = andval + t + 2 * cur;
        if (cand > best) best = cand;
    }
    return best;
};
